static int Dtool_Traverse_PGItem(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  PGItem *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_PGItem, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_PGItem(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_PGItem._PyType && DtoolInstance_TYPE(self) == &Dtool_PGItem) {
    DtoolProxy_PGItem *proxy = (DtoolProxy_PGItem *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

