static int Dtool_Traverse_PGEntry(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  PGEntry *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_PGEntry, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_PGEntry(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_PGEntry._PyType && DtoolInstance_TYPE(self) == &Dtool_PGEntry) {
    DtoolProxy_PGEntry *proxy = (DtoolProxy_PGEntry *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

